                int matchCost = (s1[i - 1] == s2[j - 1]) ? 0 : MismatchCost;
                dp[i, j] = Math.Min(
                    Math.Min(dp[i - 1, j] + GapCost, dp[i, j - 1] + GapCost),
                    dp[i - 1, j - 1] + matchCost
