    let arr2 = Array(s2)
    let m = arr1.count
    let n = arr2.count

    var dp = Array(repeating: Array(repeating: 0, count: n + 1), count: m + 1)

    for i in 0...m { dp[i][0] = i * gapCost }
    for j in 0...n { dp[0][j] = j * gapCost }

    for i in 1...max(m, 1) {
        guard m > 0 else { break }
        for j in 1...max(n, 1) {
