            let matchCost = arr1[i - 1] == arr2[j - 1] ? 0 : mismatchCost
            dp[i][j] = min(
                min(dp[i - 1][j] + gapCost, dp[i][j - 1] + gapCost),
                dp[i - 1][j - 1] + matchCost
            )
        }
    }

    return dp[m][n]
